const CHECK_SVG = "<svg fill=\"none\" stroke=\"currentColor\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\" d=\"M5 13l4 4L19 7\"/></svg>";
const X_SVG = "<svg fill=\"none\" stroke=\"currentColor\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\" d=\"M6 18L18 6M6 6l12 12\"/></svg>";
function renderPage(variant, title, message, detail) {
	const icon = variant === "success" ? CHECK_SVG : X_SVG;
	const detailHtml = detail ? `<div class="error-detail">${escapeHtml(detail)}</div>` : "";
	return `<!DOCTYPE html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Levr CLI</title><style>${PAGE_STYLES}</style></head><body><div class="card"><div class="logo"><img class="logo-light" src="data:image/png;base64," alt="Levr"><img class="logo-dark" src="data:image/png;base64," alt="Levr"></div><div class="icon-circle ${variant}">${icon}</div><h2>${escapeHtml(title)}</h2><p>${escapeHtml(message)}</p>` + detailHtml + "</div></body></html>";
}
function escapeHtml(str) {
	return str.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;");
}
/**
* Start a temporary HTTP server on 127.0.0.1 with a random port.
* Waits for an OAuth callback at /callback?code=... and returns the code.
*/
function startCallbackServer(options = {}) {
	const timeout = options.timeout ?? 12e4;
	const expectedState = options.expectedState;
	let resolvePort;
	let resolveCode;
	let rejectCode;
	const portPromise = new Promise((resolve) => {
		resolvePort = resolve;
	});
	const codePromise = new Promise((resolve, reject) => {
		resolveCode = resolve;
		rejectCode = reject;
	});
	const server = createServer((req, res) => {
		const url = new URL(req.url ?? "/", `http://127.0.0.1`);
		if (url.pathname === "/callback") {
			const code = url.searchParams.get("code");
			const error = url.searchParams.get("error");
			if (error) {
				res.writeHead(200, { "Content-Type": "text/html" });
				res.end(renderPage("error", "Authentication failed", "You can close this window.", error));
				clearTimeout(timer);
				rejectCode(/* @__PURE__ */ new Error(`OAuth error: ${error}`));
				server.close();
				return;
			}
			if (code) {
				const returnedState = url.searchParams.get("state");
				if (expectedState && returnedState !== expectedState) {
					res.writeHead(200, { "Content-Type": "text/html" });
					res.end(renderPage("error", "Authentication failed", "You can close this window.", "Invalid state parameter."));
					clearTimeout(timer);
					rejectCode(/* @__PURE__ */ new Error("OAuth state mismatch (possible CSRF)"));
					server.close();
					return;
				}
				res.writeHead(200, { "Content-Type": "text/html" });
				res.end(renderPage("success", "Authentication successful!", "You can close this window and return to the terminal."));
				clearTimeout(timer);
				resolveCode({ code });
				server.close();
				return;
			}
		}
		res.writeHead(404);
		res.end("Not found");
	});
	const timer = setTimeout(() => {
		rejectCode(/* @__PURE__ */ new Error("Authentication timed out. No callback received."));
		server.close();
	}, timeout);
	server.listen(0, "127.0.0.1", () => {
		const addr = server.address();
		if (addr && typeof addr !== "string") resolvePort(addr.port);
	});
	return {
		port: portPromise,
		code: codePromise,
		close: () => {
			clearTimeout(timer);
			server.close();
		}
	};
}

