//#region src/utils/sleep.ts
function sleep(ms) {
	return new Promise((resolve) => setTimeout(resolve, ms));
}

//#endregion
//#region src/auth/device-flow.ts
/**
* Request a device authorization code from the backend.
*/
async function requestDeviceCode() {
	const apiUrl = getApiUrl();
	let res;
	try {
		res = await fetch(`${apiUrl}/v1/oauth/device/authorize`, {
			method: "POST",
			headers: { "Content-Type": "application/x-www-form-urlencoded" },
			body: new URLSearchParams({
				client_id: CLI_CLIENT_ID,
				scope: "read:own write:own"
			})
		});
	} catch {
		throw new Error(`Could not reach ${apiUrl} — check the URL and your network connection.`);
	}
	if (!res.ok) {
		const body = await res.text();
		throw new Error(`Failed to request device code (${res.status}): ${body}`);
	}
	return await res.json();
}
/**
* Poll the token endpoint for device flow approval.
* Returns tokens on success, throws on error/expiry/denial.
*/
async function pollForDeviceToken(options) {
	const apiUrl = getApiUrl();
	let interval = options.interval;
	const deadline = Date.now() + options.expiresIn * 1e3;
	while (Date.now() < deadline) {
		await sleep(interval * 1e3);
		const res = await fetch(`${apiUrl}/v1/oauth/token`, {
			method: "POST",
			headers: { "Content-Type": "application/x-www-form-urlencoded" },
			body: new URLSearchParams({
				grant_type: "urn:ietf:params:oauth:grant-type:device_code",
				device_code: options.deviceCode,
				client_id: CLI_CLIENT_ID
			})
		});
		if (res.ok) return await res.json();
		const body = await res.json();
		switch (body.error) {
			case "authorization_pending":
				options.onPending?.();
				continue;
			case "slow_down":
				interval += 5;
				continue;
			case "expired_token": throw new Error("Device code expired. Please try again.");
			case "access_denied": throw new Error("Authorization denied by user.");
			default: throw new Error(`Unexpected error: ${body.error}`);
		}
	}
	throw new Error("Device code expired. Please try again.");
}

//#endregion
//#region src/commands/auth/loginHandler.ts
function formatCountdown(ms) {
	const totalSec = Math.max(0, Math.ceil(ms / 1e3));
	return `${Math.floor(totalSec / 60)}:${(totalSec % 60).toString().padStart(2, "0")}`;
}
async function loginHandler(flags) {
	await performLogin(this, {
		deviceCode: flags["device-code"],
		url: flags.url
	});
}
/**
* Run the login flow (PKCE or device code). Reusable outside the Stricli
* handler (levr init composes it). Returns true on success; on failure the
* error has been printed and `exitCode` set.
*/
async function performLogin(ctx, options) {
	if (options.url) setSessionApiUrl(options.url);
	if (options.deviceCode) return deviceCodeLogin(ctx);
	return pkceLogin(ctx);
}
async function pkceLogin(ctx) {
	const apiUrl = getApiUrl();
	let authUrl;
	try {
		authUrl = getAuthUrl();
	} catch (err) {
		ctx.logger.error(err instanceof Error ? err.message : "Invalid auth server configuration.");
		ctx.process.exitCode = 1;
		return false;
	}
	const codeVerifier = generateCodeVerifier();
	const codeChallenge = generateCodeChallenge(codeVerifier);
	const state = randomBytes(16).toString("hex");
	const { port: portPromise, code: codePromise, close } = startCallbackServer({
		timeout: 12e4,
		expectedState: state
	});
	const redirectUri = `http://127.0.0.1:${await portPromise}/callback`;
	const params = new URLSearchParams({
		response_type: "code",
		client_id: CLI_CLIENT_ID,
		redirect_uri: redirectUri,
		code_challenge: codeChallenge,
		code_challenge_method: "S256",
		scope: "read:own write:own",
		state
	});
	const authorizeUrl = `${authUrl}/auth/oauth/authorize?${params.toString()}`;
	ctx.process.stdout.write("Opening browser to authenticate...\n\n");
	ctx.process.stdout.write(`  If the browser doesn't open, visit:\n  ${chalk.cyan(authorizeUrl)}\n\n`);
	try {
		await (await import("open")).default(authorizeUrl);
	} catch {}
	const timeoutMs = 12e4;
	const deadline = Date.now() + timeoutMs;
	const countdownTimer = setInterval(() => {
		const remaining = deadline - Date.now();
		ctx.process.stdout.write(`\rWaiting for authentication... ${chalk.dim(`(${formatCountdown(remaining)})`)}`);
	}, 1e3);
	ctx.process.stdout.write(`Waiting for authentication... ${chalk.dim(`(${formatCountdown(timeoutMs)})`)}`);
	let authCode;
	try {
		authCode = (await codePromise).code;
	} catch (err) {
		close();
		clearInterval(countdownTimer);
		ctx.process.stdout.write("\n");
		ctx.logger.error(err instanceof Error ? err.message : "Authentication failed.");
		ctx.process.exitCode = 1;
		return false;
	}
	clearInterval(countdownTimer);
	try {
		const tokenRes = await fetch(`${apiUrl}/v1/oauth/token`, {
			method: "POST",
			headers: { "Content-Type": "application/x-www-form-urlencoded" },
			body: new URLSearchParams({
				grant_type: "authorization_code",
				code: authCode,
				redirect_uri: redirectUri,
				client_id: CLI_CLIENT_ID,
				code_verifier: codeVerifier
			})
		});
		if (!tokenRes.ok) {
			const errBody = await tokenRes.text();
			throw new Error(`Token exchange failed (${tokenRes.status}): ${errBody}`);
		}
		return await saveTokensAndFinish(ctx, await tokenRes.json());
	} catch (err) {
		ctx.process.stdout.write("\n");
		ctx.logger.error(err instanceof Error ? err.message : "Token exchange failed.");
		ctx.process.exitCode = 1;
		return false;
	}
}
async function deviceCodeLogin(ctx) {
	try {
		const device = await requestDeviceCode();
		ctx.process.stdout.write(`\nVisit: ${chalk.cyan(device.verification_uri)}\n`);
		ctx.process.stdout.write(`Enter code: ${chalk.bold.yellow(device.user_code)}\n\n`);
		const deviceDeadline = Date.now() + device.expires_in * 1e3;
		const deviceTimer = setInterval(() => {
			const remaining = deviceDeadline - Date.now();
			ctx.process.stdout.write(`\rWaiting for authorization... ${chalk.dim(`(${formatCountdown(remaining)})`)}`);
		}, 1e3);
		ctx.process.stdout.write(`Waiting for authorization... ${chalk.dim(`(${formatCountdown(device.expires_in * 1e3)})`)}`);
		let tokenData;
		try {
			tokenData = await pollForDeviceToken({
				deviceCode: device.device_code,
				interval: device.interval,
				expiresIn: device.expires_in
			});
		} catch (err) {
			clearInterval(deviceTimer);
			throw err;
		}
		clearInterval(deviceTimer);
		return await saveTokensAndFinish(ctx, tokenData);
	} catch (err) {
		ctx.process.stdout.write("\n");
		ctx.logger.error(err instanceof Error ? err.message : "Device flow failed.");
		ctx.process.exitCode = 1;
		return false;
	}
}
async function saveTokensAndFinish(ctx, tokenData) {
	const apiUrl = getApiUrl();
	configureClient({
		token: tokenData.access_token,
		type: "jwt"
	});
	const user = tokenData.user;
	if (!user) {
		ctx.process.stdout.write("\n");
		ctx.logger.error("Token response missing user data.");
		ctx.process.exitCode = 1;
		return false;
	}
	writeCredentials({
		version: 1,
		api_url: apiUrl,
		access_token: tokenData.access_token,
		refresh_token: tokenData.refresh_token,
		expires_at: new Date(Date.now() + tokenData.expires_in * 1e3).toISOString(),
		user: {
			id: user.id,
			email: user.email,
			workspace_id: user.workspace_id
		}
	});
	ctx.process.stdout.write(` ${chalk.green("done")}\n\n`);
	ctx.logger.success(`Logged in as ${chalk.bold(user.email)}`);
	ctx.process.stdout.write("Credentials saved.\n");
	const wsResult = await autoSelectWorkspace();
	if (wsResult.kind === "single") ctx.process.stdout.write(`Workspace: ${chalk.bold(wsResult.workspaceName)}\n`);
	else if (wsResult.kind === "multiple") ctx.process.stdout.write(`\n${wsResult.count} workspaces available. Run ${chalk.cyan("'levr workspace list'")} to see them.\n`);
	return true;
}

//#endregion
export { loginHandler };